#!/usr/bin/env node
// ---------------------------------------------------------------------------
// WebCure CLI -- Thin wrapper for the file bridge.
// Auto-generated by the WebCure extension. Do not edit.
//
// Usage:
//   node .webcure/cli.js <command> [key=value ...]
//
// Examples:
//   node .webcure/cli.js navigate url=https://google.com
//   node .webcure/cli.js click target="Sign In"
//   node .webcure/cli.js typeText text="hello" into="Search"
//   node .webcure/cli.js screenshot
//   node .webcure/cli.js snapshot
//   node .webcure/cli.js find text="Login"
//   node .webcure/cli.js interact action=click ref=e1
//   node .webcure/cli.js closeBrowser
//   node .webcure/cli.js help
// ---------------------------------------------------------------------------

const fs = require('fs');
const path = require('path');

const BRIDGE_DIR = __dirname;
const INPUT = path.join(BRIDGE_DIR, 'input.json');
const OUTPUT = path.join(BRIDGE_DIR, 'output.json');

const HELP = [
    'WebCure CLI -- Browser automation from the terminal.',
    '',
    'Usage: node .webcure/cli.js <command> [key=value ...]',
    '',
    'Commands:',
    '  launchBrowser [url=...] [headless=true]',
    '  closeBrowser',
    '  navigate        url=<URL>',
    '  click           target=<text|selector> [ref=<eN>] [below=...] [above=...]',
    '  doubleClick     target=<text|selector> [ref=<eN>]',
    '  rightClick      target=<text|selector> [ref=<eN>]',
    '  typeText        text=<text> [into=<field>] [ref=<eN>] [below=...] [above=...]',
    '  pressKey        key=<key>',
    '  hover           target=<text|selector> [ref=<eN>] [below=...] [above=...]',
    '  scrollDown      [pixels=<n>]',
    '  scrollUp        [pixels=<n>]',
    '  scrollRight     [pixels=<n>]',
    '  scrollLeft      [pixels=<n>]',
    '  refresh',
    '  goBack',
    '  goForward',
    '  screenshot      [filename=<name>] [ref=<eN>] [type=png|jpeg] [outputPath=<path>]',
    '  selectOption    comboBox=<selector> value=<option> [ref=<eN>]',
    '  switchWindow    title=<substring>',
    '  resizeBrowser   width=<n> height=<n>  OR  preset=<name>',
    '  fullscreenBrowser',
    '  waitForText     text=<text> [state=visible|hidden] [timeout=<ms>]',
    '  waitForElement  target=<selector|text> [ref=<eN>] [state=visible|hidden|attached|detached]',
    '  wait            ms=<milliseconds>',
    '  listTabs',
    '  newTab          [url=<URL>]',
    '  closeTab        index=<n>',
    '  selectTab       index=<n>',
    '  evaluate        expression=<js> [ref=<eN>] [target=<selector>]',
    '  consoleMessages [onlyErrors=true]',
    '  networkRequests',
    '  handleDialog    [accept=true|false] [promptText=<text>]',
    '  getDialogText',
    '  uploadFile      paths=<path1,path2> [selector=<css>]',
    '  scrapeMenu',
    '  scrapePage',
    '  getAccessibilityTree',
    '  snapshot        (get accessibility tree with element refs e1, e2, ...)',
    '  find            [text=<visible text>] [selector=<css>] [near=...] [toLeftOf=...] [toRightOf=...]',
    '  interact        action=<click|type|hover|clear|select|focus|check|uncheck|press> [ref=<eN>]',
    '  typeFromFile    filePath=<path> [ref=<eN>] [text=...] [selector=...] [submit=true]',
    '  fillForm        fields=<json array of {name,type,ref,value}>',
    '  dragTo          source=<text|selector> target=<text|selector>',
    '  startRecording',
    '  stopRecording',
    '  startStepRecorder [url=<URL>]   (Record Steps - Automatic)',
    '  stopStepRecorder                (Stop step recording)',
    '  restartExtensionHost            (Restart extension host after VSIX install)',
    '  runScript       file=<path_to_json>',
    '  getPageInfo',
    '  getPageContent',
    '  getPageText',
    '  extract         [selector=<css>] [maxLength=<n>]',
    '  highlight       target=<text|selector>',
    '  help',
].join('\n');

// --- Parse arguments -------------------------------------------------------

const args = process.argv.slice(2);
if (args.length === 0 || args[0] === 'help' || args[0] === '--help') {
    console.log(HELP);
    process.exit(0);
}

const command = args[0];
const cmdArgs = {};

for (let i = 1; i < args.length; i++) {
    const eq = args[i].indexOf('=');
    if (eq > 0) {
        const key = args[i].slice(0, eq);
        let val = args[i].slice(eq + 1);
        // Parse booleans and numbers
        if (val === 'true') val = true;
        else if (val === 'false') val = false;
        else if (/^\d+$/.test(val)) val = parseInt(val, 10);
        cmdArgs[key] = val;
    }
}

// --- Write command, wait for result ----------------------------------------

const LOCK_TIMEOUT_MS = 10000;
const lockStart = Date.now();
while (fs.existsSync(INPUT)) {
    if (Date.now() - lockStart > LOCK_TIMEOUT_MS) {
        console.error('Another command is still being processed. Try again.');
        process.exit(1);
    }
    const waitUntil = Date.now() + 50;
    while (Date.now() < waitUntil) { /* spin */ }
}

// Clean up any previous output.
try { fs.unlinkSync(OUTPUT); } catch { }

// Write the command.
fs.writeFileSync(INPUT, JSON.stringify({ command, args: cmdArgs }, null, 2));

// Poll for result.
let TIMEOUT_MS = 30000;
if (command === 'runScript') {
    TIMEOUT_MS = 300000;
}
const POLL_MS = 100;

const start = Date.now();
let inputConsumed = false;

function poll() {
    if (!inputConsumed && !fs.existsSync(INPUT)) {
        inputConsumed = true;
    }

    if (inputConsumed && fs.existsSync(OUTPUT)) {
        try {
            const raw = fs.readFileSync(OUTPUT, 'utf-8');
            const result = JSON.parse(raw);
            console.log(JSON.stringify(result, null, 2));
            process.exit(result.status === 'ok' ? 0 : 1);
        } catch (e) {
            console.error('Error reading result:', e.message);
            process.exit(1);
        }
    }

    if (Date.now() - start > TIMEOUT_MS) {
        const timeoutSec = Math.round(TIMEOUT_MS / 1000);
        console.error(`Timeout: WebCure extension did not respond within ${timeoutSec}s.`);
        console.error('Is the extension running in your IDE?');
        try { fs.unlinkSync(INPUT); } catch { }
        process.exit(1);
    }

    setTimeout(poll, POLL_MS);
}

poll();
